module Foo(
  input  clkIn, a,
  output clkOut, b);

  wire _T;
  reg  r;

  assign _T = clkIn;
  wire _T_0 = _T;
  always @(posedge _T_0)
    r <= a;
  assign clkOut = _T_0;
  assign b = r;
endmodule

input clkIn;
wire w1;
wire w2 = w1;
reg r;
assign w1 = clkIn;
always @(posedge w2)
  r <= 1'b1;

module ClkPassThru(
  input  clk_in,
  input  d,
  output clk_out,
  output q);

  wire clk_int;
  reg  r;

  assign clk_int = clk_in;
  assign clk_out  = clk_int;
  always @(posedge clk_int)
    r <= d;
  assign q = r;
endmodule
